import React, { useState } from 'react';

function CloudScope({ words }) {
  const [selectedWord, setSelectedWord] = useState(null);

  if (selectedWord) {
    return (
      <div style={{ padding: '40px', textAlign: 'center' }}>
        <h2>Drill Down: {selectedWord}</h2>
        <button onClick={() => setSelectedWord(null)}>Back to Cloud</button>
      </div>
    );
  }

  // Purely random, organic layout logic
  return (
    <div style={{
      display: 'flex',
      flexWrap: 'wrap',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '50px',
      gap: '10px',
      maxWidth: '600px',
      margin: '40px auto',
      minHeight: '400px'
    }}>
      {Object.entries(words).map(([word, count]) => (
        <span
          key={word}
          onClick={() => setSelectedWord(word)}
          style={{
            fontSize: `${Math.min(count * 5 + 15, 60)}px`,
            color: `hsl(${Math.random() * 360}, 70%, 40%)`,
            cursor: 'pointer',
            padding: '5px',
            transform: `rotate(${Math.random() * 30 - 15}deg)`, // Organic tilt
            display: 'inline-block'
          }}
        >
          {word}
        </span>
      ))}
    </div>
  );
}

export default CloudScope;
